1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! PM's process table (slice 4.5) — the minix.rs `mproc`.
4	//!
5	//! Modeled on MINIX 3 `servers/pm/mproc.h`: a static table indexed by the
6	//! *same* process number as the kernel's proc table, each entry carrying the
7	//! POSIX-visible identity (pid, parent) the kernel deliberately knows nothing
8	//! about. MINIX seeds it from `sys_getimage`; minix.rs seeds it from the
9	//! shared boot-image constants in `kernel-shared::com` — same information,
10	//! no kernel call needed while the boot layout is static.
11	//!
12	//! Seeding (mirrors MINIX `pm_init`): PM is pid 0 and its own parent; INIT is
13	//! pid 1; every other boot server takes the next free pid in slot order with
14	//! RS as parent (RS itself is parented to PM so no server is its own
15	//! ancestor); the Phase-4 demo stubs are ordinary user processes parented to
16	//! INIT. Boot servers carry [`MF_PRIV_PROC`], which the kill path refuses to
17	//! terminate — delivering signals *to* system processes (MINIX's sig2mess)
18	//! waits for a consumer (RS restarts).
19	//!
20	//! Table shape follows `vm/region.rs` / `ds/registry.rs`: a fixed-capacity
21	//! `UnsafeCell` static behind a `#[repr(transparent)]` newtype, with all
22	//! logic in pure `*_in` helpers that carry the host unit tests; the thin
23	//! wrappers reaching the static are the only `unsafe`.
24	
25	use core::cell::UnsafeCell;
26	
27	use minixrs_kernel_shared::com::{
28	    INIT_PROC_NR, NR_BOOT_PROCS, NR_STUB_PROCS, PM_PROC_NR, RS_PROC_NR, boot_endpoint,
29	};
30	use minixrs_kernel_shared::endpoint::{Endpoint, ProcNr};
31	
32	/// Table capacity. Slots `0..NR_BOOT_PROCS + NR_STUB_PROCS` (= 16) are seeded
33	/// at init; the pool above that ([`FORK_POOL_BASE`]`..NR_MPROCS`) is where 4.6's
34	/// fork allocates children.
35	pub const NR_MPROCS: usize = 32;
36	
37	/// First slot fork may allocate. Boot servers + demo stubs own `[0, 16)`; forked
38	/// children land in `[FORK_POOL_BASE, NR_MPROCS)`. A child's slot index is also
39	/// its kernel proc number, so this range must stay within the kernel proc table
40	/// and within VM's `MAX_CLIENTS` region-table cap (both hold).
41	pub const FORK_POOL_BASE: usize = NR_BOOT_PROCS + NR_STUB_PROCS;
42	
43	/// Entry holds a live process.
44	pub const MF_IN_USE: u8 = 1 << 0;
45	/// Boot system process — the kill path refuses to terminate it.
46	pub const MF_PRIV_PROC: u8 = 1 << 1;
47	/// Terminated (a zombie): the process is gone at the kernel level (`SYS_EXIT`
48	/// ran) but its `mproc` slot is retained — holding the exit status — until its
49	/// parent `wait()`s and reaps it. Set by both the exit path ([`set_zombie_in`],
50	/// with a real status) and the kill path ([`handle_kill_in`]).
51	pub const MF_DEAD: u8 = 1 << 2;
52	/// This process is a parent blocked in `wait()` with no reapable child yet;
53	/// when a child exits, [`set_zombie_in`]'s caller wakes it directly.
54	pub const MF_WAITING: u8 = 1 << 3;
55	
56	/// One `mproc` entry. The slot index *is* the kernel proc number, but once slots
57	/// recycle (4.6 fork/exit bump the endpoint generation) `boot_endpoint(slot)` no
58	/// longer identifies the occupant, so the generation-aware endpoint is stored
59	/// explicitly.
60	#[derive(Clone, Copy)]
61	pub struct MProc {
62	    pub pid: i32,
63	    pub parent_slot: usize,
64	    /// Generation-aware endpoint of this process (from `SYS_FORK` for children,
65	    /// `boot_endpoint(slot)` for seeded boot/stub procs).
66	    pub endpoint: Endpoint,
67	    /// Encoded exit status stored while the process is a zombie (`MF_DEAD`).
68	    pub exit_status: i32,
69	    pub flags: u8,
70	}
71	
72	impl MProc {
73	    pub const EMPTY: Self = Self {
74	        pid: 0,
75	        parent_slot: 0,
76	        endpoint: 0,
77	        exit_status: 0,
78	        flags: 0,
79	    };
80	}
81	
82	/// Disposition of a kill request against a slot.
83	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
84	pub enum KillAction {
85	    /// Ordinary user process: caller should terminate it (`SYS_EXIT`).
86	    Terminate,
87	    /// Boot system process: refuse — sig2mess is a later slice.
88	    SkipPrivileged,
89	    /// Unknown, unused, or already-dead slot: nothing to do.
90	    NotFound,
91	}
92	
93	/// Seed the table with the boot image + demo stubs. Pure; called once from
94	/// PM's SEF init via [`seed`].
95	fn seed_in(t: &mut [MProc; NR_MPROCS]) {
96	    let pm = PM_PROC_NR.get() as usize;
97	    let rs = RS_PROC_NR.get() as usize;
98	    let init = INIT_PROC_NR.get() as usize;
99	
100	    // Every seeded proc is at generation 0, so its endpoint is `boot_endpoint`
101	    // of its slot (= kernel proc number). Forked children later store the
102	    // generation-aware endpoint `SYS_FORK` hands back.
103	    let ep = |slot: usize| boot_endpoint(ProcNr::new(slot as i32));
104	
105	    // PM: pid 0, its own parent (MINIX `pm_init` patches itself the same way).
106	    t[pm] = MProc {
107	        pid: 0,
108	        parent_slot: pm,
109	        endpoint: ep(pm),
110	        exit_status: 0,
111	        flags: MF_IN_USE | MF_PRIV_PROC,
112	    };
113	    // INIT: pid 1. Not running yet (no ELF until 4.8) but seeded so the demo
114	    // stubs have a parent with a pid.
115	    t[init] = MProc {
116	        pid: 1,
117	        parent_slot: rs,
118	        endpoint: ep(init),
119	        exit_status: 0,
120	        flags: MF_IN_USE | MF_PRIV_PROC,
121	    };
122	
123	    // Remaining boot servers: next free pids in slot order, parented to RS
124	    // (the root system process) — except RS itself, parented to PM so no
125	    // process is its own ancestor besides PM.
126	    let mut next_pid = 2;
127	    for (slot, e) in t.iter_mut().enumerate().take(NR_BOOT_PROCS) {
128	        if slot == pm || slot == init {
129	            continue;
130	        }
131	        *e = MProc {
132	            pid: next_pid,
133	            parent_slot: if slot == rs { pm } else { rs },
134	            endpoint: ep(slot),
135	            exit_status: 0,
136	            flags: MF_IN_USE | MF_PRIV_PROC,
137	        };
138	        next_pid += 1;
139	    }
140	
141	    // Demo stubs: ordinary user processes, parented to INIT, pids continuing
142	    // past the servers (slots 11..=15 land on pids 11..=15).
143	    for (slot, e) in t
144	        .iter_mut()
145	        .enumerate()
146	        .skip(NR_BOOT_PROCS)
147	        .take(NR_STUB_PROCS)
148	    {
149	        *e = MProc {
150	            pid: next_pid,
151	            parent_slot: init,
152	            endpoint: ep(slot),
153	            exit_status: 0,
154	            flags: MF_IN_USE,
155	        };
156	        next_pid += 1;
157	    }
158	}
159	
160	/// Look up `(pid, ppid)` for `slot`. `None` for out-of-range, unused, or dead
161	/// slots — the caller replies `ESRCH`.
162	fn getpid_in(t: &[MProc; NR_MPROCS], slot: usize) -> Option<(i32, i32)> {
163	    let e = t.get(slot)?;
164	    if e.flags & MF_IN_USE == 0 || e.flags & MF_DEAD != 0 {
165	        return None;
166	    }
167	    Some((e.pid, t[e.parent_slot].pid))
168	}
169	
170	/// Decide the kill disposition for `slot` and, when it is an ordinary live
171	/// user process, mark it dead. The caller performs the actual `SYS_EXIT`.
172	fn handle_kill_in(t: &mut [MProc; NR_MPROCS], slot: usize) -> KillAction {
173	    let Some(e) = t.get_mut(slot) else {
174	        return KillAction::NotFound;
175	    };
176	    if e.flags & MF_IN_USE == 0 || e.flags & MF_DEAD != 0 {
177	        return KillAction::NotFound;
178	    }
179	    if e.flags & MF_PRIV_PROC != 0 {
180	        return KillAction::SkipPrivileged;
181	    }
182	    e.flags |= MF_DEAD;
183	    KillAction::Terminate
184	}
185	
186	// ---------------------------------------------------------------------------
187	// Fork / exit / wait table management (slice 4.6b). All pure `*_in` helpers.
188	// ---------------------------------------------------------------------------
189	
190	/// True if `slot` holds a live (in-use, not-yet-reaped) process.
191	fn in_use_in(t: &[MProc; NR_MPROCS], slot: usize) -> bool {
192	    t.get(slot).is_some_and(|e| e.flags & MF_IN_USE != 0)
193	}
194	
195	/// The parent slot of `slot`, or `None` if the slot is not in use.
196	fn parent_of_in(t: &[MProc; NR_MPROCS], slot: usize) -> Option<usize> {
197	    let e = t.get(slot)?;
198	    (e.flags & MF_IN_USE != 0).then_some(e.parent_slot)
199	}
200	
201	/// The stored endpoint of `slot`, or `None` if the slot is not in use.
202	fn endpoint_of_in(t: &[MProc; NR_MPROCS], slot: usize) -> Option<Endpoint> {
203	    let e = t.get(slot)?;
204	    (e.flags & MF_IN_USE != 0).then_some(e.endpoint)
205	}
206	
207	/// First free slot in the fork pool `[FORK_POOL_BASE, NR_MPROCS)`, or `None`
208	/// when the table is full (PM replies `EAGAIN`). MINIX `do_fork` scans `mproc`
209	/// the same way; the slot index becomes the child's kernel proc number.
210	fn alloc_slot_in(t: &[MProc; NR_MPROCS]) -> Option<usize> {
211	    (FORK_POOL_BASE..NR_MPROCS).find(|&slot| t[slot].flags == 0)
212	}
213	
214	/// Next pid to assign: one past the highest pid any current entry holds (live
215	/// or zombie), so a pid is never reused while its predecessor is still around.
216	/// Pids climb monotonically as long as the high-water entry persists; after the
217	/// whole fork pool drains they may repeat — harmless, since the endpoint
218	/// generation (not the pid) is what guards slot recycling.
219	fn alloc_pid_in(t: &[MProc; NR_MPROCS]) -> i32 {
220	    let max = t
221	        .iter()
222	        .filter(|e| e.flags != 0)
223	        .map(|e| e.pid)
224	        .max()
225	        .unwrap_or(0);
226	    max + 1
227	}
228	
229	/// Populate a freshly forked child at `slot`, returning its assigned pid. The
230	/// caller passes the generation-aware endpoint `SYS_FORK` handed back.
231	fn set_child_in(
232	    t: &mut [MProc; NR_MPROCS],
233	    slot: usize,
234	    parent_slot: usize,
235	    endpoint: Endpoint,
236	) -> i32 {
237	    let pid = alloc_pid_in(t);
238	    t[slot] = MProc {
239	        pid,
240	        parent_slot,
241	        endpoint,
242	        exit_status: 0,
243	        flags: MF_IN_USE,
244	    };
245	    pid
246	}
247	
248	/// Mark `slot` a zombie (terminated, awaiting reap), recording `status`.
249	fn set_zombie_in(t: &mut [MProc; NR_MPROCS], slot: usize, status: i32) {
250	    if let Some(e) = t.get_mut(slot) {
251	        e.exit_status = status;
252	        e.flags |= MF_DEAD;
253	    }
254	}
255	
256	/// Set or clear `slot`'s `MF_WAITING` (parent blocked in `wait()`).
257	fn set_waiting_in(t: &mut [MProc; NR_MPROCS], slot: usize, waiting: bool) {
258	    if let Some(e) = t.get_mut(slot) {
259	        if waiting {
260	            e.flags |= MF_WAITING;
261	        } else {
262	            e.flags &= !MF_WAITING;
263	        }
264	    }
265	}
266	
267	/// True if `slot` is a parent blocked in `wait()`.
268	fn is_waiting_in(t: &[MProc; NR_MPROCS], slot: usize) -> bool {
269	    t.get(slot).is_some_and(|e| e.flags & MF_WAITING != 0)
270	}
271	
272	/// First zombie child of `parent_slot`, as `(slot, pid, exit_status)`, or `None`.
273	fn find_zombie_child_in(t: &[MProc; NR_MPROCS], parent_slot: usize) -> Option<(usize, i32, i32)> {
274	    t.iter().enumerate().find_map(|(slot, e)| {
275	        (e.flags & MF_IN_USE != 0 && e.flags & MF_DEAD != 0 && e.parent_slot == parent_slot)
276	            .then_some((slot, e.pid, e.exit_status))
277	    })
278	}
279	
280	/// True if `parent_slot` has at least one still-live (non-zombie) child.
281	fn has_live_child_in(t: &[MProc; NR_MPROCS], parent_slot: usize) -> bool {
282	    t.iter().enumerate().any(|(slot, e)| {
283	        slot != parent_slot
284	            && e.flags & MF_IN_USE != 0
285	            && e.flags & MF_DEAD == 0
286	            && e.parent_slot == parent_slot
287	    })
288	}
289	
290	/// Release `slot` back to the free pool (fork rollback, or reaping a zombie).
291	fn cleanup_in(t: &mut [MProc; NR_MPROCS], slot: usize) {
292	    if let Some(e) = t.get_mut(slot) {
293	        *e = MProc::EMPTY;
294	    }
295	}
296	
297	/// `UnsafeCell`-wrapped static table. See the module note for the
298	/// single-mutator invariant that makes the `Sync` impl sound.
299	#[repr(transparent)]
300	struct Table(UnsafeCell<[MProc; NR_MPROCS]>);
301	
302	// SAFETY: PM is a single-threaded EL0 process with no interrupt handlers of
303	// its own; the table is only ever accessed from PM's straight-line SEF
304	// init + receive loop, so there is never concurrent access.
305	unsafe impl Sync for Table {}
306	
307	static TABLE: Table = Table(UnsafeCell::new([MProc::EMPTY; NR_MPROCS]));
308	
309	/// Seed the global table from the boot-image constants.
310	pub fn seed() {
311	    // SAFETY: single-mutator invariant (module note); no other reference into
312	    // the table is live during PM's straight-line init.
313	    let t = unsafe { &mut *TABLE.0.get() };
314	    seed_in(t);
315	}
316	
317	/// Look up `(pid, ppid)` for `slot` in the global table.
318	pub fn getpid(slot: usize) -> Option<(i32, i32)> {
319	    // SAFETY: single-mutator invariant (module note); shared read, no live `&mut`.
320	    let t = unsafe { &*TABLE.0.get() };
321	    getpid_in(t, slot)
322	}
323	
324	/// Decide (and record) the kill disposition for `slot` in the global table.
325	pub fn handle_kill(slot: usize) -> KillAction {
326	    // SAFETY: single-mutator invariant (module note); no other reference into
327	    // the table is live during PM's straight-line loop.
328	    let t = unsafe { &mut *TABLE.0.get() };
329	    handle_kill_in(t, slot)
330	}
331	
332	// Fork / exit / wait wrappers over the global table. Each is the only `unsafe`
333	// touching the static; the logic lives in the host-tested `*_in` helpers above.
334	// SAFETY (all): single-mutator invariant (module note); PM's straight-line loop
335	// never holds another live reference into the table across these calls.
336	
337	/// True if `slot` holds a live process.
338	pub fn in_use(slot: usize) -> bool {
339	    in_use_in(unsafe { &*TABLE.0.get() }, slot)
340	}
341	
342	/// The parent slot of `slot`, or `None` if not in use.
343	pub fn parent_of(slot: usize) -> Option<usize> {
344	    parent_of_in(unsafe { &*TABLE.0.get() }, slot)
345	}
346	
347	/// The stored endpoint of `slot`, or `None` if not in use.
348	pub fn endpoint_of(slot: usize) -> Option<Endpoint> {
349	    endpoint_of_in(unsafe { &*TABLE.0.get() }, slot)
350	}
351	
352	/// Allocate a free fork-pool slot, or `None` if the table is full.
353	pub fn alloc_slot() -> Option<usize> {
354	    alloc_slot_in(unsafe { &*TABLE.0.get() })
355	}
356	
357	/// Populate a forked child at `slot`; returns its assigned pid.
358	pub fn set_child(slot: usize, parent_slot: usize, endpoint: Endpoint) -> i32 {
359	    set_child_in(unsafe { &mut *TABLE.0.get() }, slot, parent_slot, endpoint)
360	}
361	
362	/// Mark `slot` a zombie carrying `status`.
363	pub fn set_zombie(slot: usize, status: i32) {
364	    set_zombie_in(unsafe { &mut *TABLE.0.get() }, slot, status)
365	}
366	
367	/// Set or clear `slot`'s waiting flag.
368	pub fn set_waiting(slot: usize, waiting: bool) {
369	    set_waiting_in(unsafe { &mut *TABLE.0.get() }, slot, waiting)
370	}
371	
372	/// True if `slot` is a parent blocked in `wait()`.
373	pub fn is_waiting(slot: usize) -> bool {
374	    is_waiting_in(unsafe { &*TABLE.0.get() }, slot)
375	}
376	
377	/// First zombie child of `parent_slot`, as `(slot, pid, exit_status)`.
378	pub fn find_zombie_child(parent_slot: usize) -> Option<(usize, i32, i32)> {
379	    find_zombie_child_in(unsafe { &*TABLE.0.get() }, parent_slot)
380	}
381	
382	/// True if `parent_slot` has at least one still-live child.
383	pub fn has_live_child(parent_slot: usize) -> bool {
384	    has_live_child_in(unsafe { &*TABLE.0.get() }, parent_slot)
385	}
386	
387	/// Release `slot` back to the free pool.
388	pub fn cleanup(slot: usize) {
389	    cleanup_in(unsafe { &mut *TABLE.0.get() }, slot)
390	}
391	
392	#[cfg(test)]
393	mod tests {
394	    use super::*;
395	    use minixrs_kernel_shared::com::{
396	        SCHED_PROC_NR, STUB_A_PROC_NR, STUB_D_PROC_NR, STUB_E_PROC_NR, VFS_PROC_NR, VM_PROC_NR,
397	    };
398	
399	    fn seeded() -> [MProc; NR_MPROCS] {
400	        let mut t = [MProc::EMPTY; NR_MPROCS];
401	        seed_in(&mut t);
402	        t
403	    }
404	
405	    #[test]
406	    fn seed_assigns_boot_pids() {
407	        let t = seeded();
408	        // PM pid 0, INIT pid 1, then slot order: VFS(1)=2, RS(2)=3 … SCHED(9)=10.
409	        assert_eq!(t[PM_PROC_NR.get() as usize].pid, 0);
410	        assert_eq!(t[INIT_PROC_NR.get() as usize].pid, 1);
411	        assert_eq!(t[VFS_PROC_NR.get() as usize].pid, 2);
412	        assert_eq!(t[RS_PROC_NR.get() as usize].pid, 3);
413	        assert_eq!(t[VM_PROC_NR.get() as usize].pid, 8);
414	        assert_eq!(t[SCHED_PROC_NR.get() as usize].pid, 10);
415	        for (slot, e) in t.iter().enumerate().take(NR_BOOT_PROCS) {
416	            assert_eq!(e.flags, MF_IN_USE | MF_PRIV_PROC, "slot {slot}");
417	        }
418	    }
419	
420	    #[test]
421	    fn seed_stub_pids_continue() {
422	        let t = seeded();
423	        for (i, slot) in (NR_BOOT_PROCS..NR_BOOT_PROCS + NR_STUB_PROCS).enumerate() {
424	            assert_eq!(t[slot].pid, 11 + i as i32);
425	            assert_eq!(t[slot].flags, MF_IN_USE, "stubs are not PRIV_PROC");
426	            assert_eq!(t[slot].parent_slot, INIT_PROC_NR.get() as usize);
427	        }
428	    }
429	
430	    #[test]
431	    fn seed_pids_are_unique() {
432	        let t = seeded();
433	        let mut seen = [false; 64];
434	        for e in t.iter().filter(|e| e.flags & MF_IN_USE != 0) {
435	            let pid = e.pid as usize;
436	            assert!(!seen[pid], "duplicate pid {pid}");
437	            seen[pid] = true;
438	        }
439	    }
440	
441	    #[test]
442	    fn getpid_returns_pid_and_ppid() {
443	        let t = seeded();
444	        // PM is its own parent: (0, 0).
445	        assert_eq!(getpid_in(&t, PM_PROC_NR.get() as usize), Some((0, 0)));
446	        // VM's parent is RS (pid 3).
447	        assert_eq!(getpid_in(&t, VM_PROC_NR.get() as usize), Some((8, 3)));
448	        // Stubs are parented to INIT (pid 1).
449	        assert_eq!(getpid_in(&t, STUB_A_PROC_NR.get() as usize), Some((11, 1)));
450	        assert_eq!(getpid_in(&t, STUB_E_PROC_NR.get() as usize), Some((15, 1)));
451	    }
452	
453	    #[test]
454	    fn getpid_unknown_slot_is_none() {
455	        let t = seeded();
456	        assert_eq!(getpid_in(&t, 16), None, "unseeded slot");
457	        assert_eq!(getpid_in(&t, NR_MPROCS), None, "out of range");
458	    }
459	
460	    #[test]
461	    fn getpid_dead_slot_is_none() {
462	        let mut t = seeded();
463	        let d = STUB_D_PROC_NR.get() as usize;
464	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
465	        assert_eq!(getpid_in(&t, d), None, "terminated proc has no pid");
466	    }
467	
468	    #[test]
469	    fn kill_user_proc_terminates_and_marks_dead() {
470	        let mut t = seeded();
471	        let d = STUB_D_PROC_NR.get() as usize;
472	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
473	        assert_ne!(t[d].flags & MF_DEAD, 0);
474	    }
475	
476	    #[test]
477	    fn kill_priv_proc_is_skipped() {
478	        let mut t = seeded();
479	        let vm = VM_PROC_NR.get() as usize;
480	        assert_eq!(handle_kill_in(&mut t, vm), KillAction::SkipPrivileged);
481	        assert_eq!(t[vm].flags & MF_DEAD, 0, "server must not be marked dead");
482	    }
483	
484	    #[test]
485	    fn kill_dead_or_unknown_is_notfound() {
486	        let mut t = seeded();
487	        let d = STUB_D_PROC_NR.get() as usize;
488	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
489	        // A second kill on the same (now dead) slot finds nothing to do.
490	        assert_eq!(handle_kill_in(&mut t, d), KillAction::NotFound);
491	        assert_eq!(handle_kill_in(&mut t, 20), KillAction::NotFound);
492	        assert_eq!(handle_kill_in(&mut t, NR_MPROCS), KillAction::NotFound);
493	    }
494	
495	    // --- Fork / exit / wait helpers (slice 4.6b) ---------------------------
496	
497	    #[test]
498	    fn seed_stores_boot_endpoints() {
499	        let t = seeded();
500	        // Seeded procs are generation 0, so endpoint == boot_endpoint(slot).
501	        let e = STUB_E_PROC_NR.get() as usize;
502	        assert_eq!(t[e].endpoint, boot_endpoint(ProcNr::new(e as i32)));
503	        assert_eq!(endpoint_of_in(&t, e), Some(t[e].endpoint));
504	    }
505	
506	    #[test]
507	    fn alloc_slot_returns_first_free_fork_pool_slot() {
508	        let mut t = seeded();
509	        // Seeded slots stop at FORK_POOL_BASE (16); the first free slot is it.
510	        assert_eq!(alloc_slot_in(&t), Some(FORK_POOL_BASE));
511	        // Occupy it, and the next free slot moves up by one.
512	        set_child_in(
513	            &mut t,
514	            FORK_POOL_BASE,
515	            STUB_E_PROC_NR.get() as usize,
516	            0x1234,
517	        );
518	        assert_eq!(alloc_slot_in(&t), Some(FORK_POOL_BASE + 1));
519	    }
520	
521	    #[test]
522	    fn alloc_slot_none_when_pool_full() {
523	        let mut t = seeded();
524	        for slot in FORK_POOL_BASE..NR_MPROCS {
525	            set_child_in(&mut t, slot, 0, 0x1000 + slot as i32);
526	        }
527	        assert_eq!(alloc_slot_in(&t), None);
528	    }
529	
530	    #[test]
531	    fn set_child_assigns_monotonic_pid_and_records_fields() {
532	        let mut t = seeded();
533	        let parent = STUB_E_PROC_NR.get() as usize; // pid 15
534	        let slot = alloc_slot_in(&t).unwrap();
535	        let pid = set_child_in(&mut t, slot, parent, 0xABCD);
536	        // Highest seeded pid is 15 (stub E) → child gets 16.
537	        assert_eq!(pid, 16);
538	        assert!(in_use_in(&t, slot));
539	        assert_eq!(parent_of_in(&t, slot), Some(parent));
540	        assert_eq!(endpoint_of_in(&t, slot), Some(0xABCD));
541	        // A live child is not yet a getpid-visible... it is, actually: live.
542	        assert_eq!(getpid_in(&t, slot), Some((16, 15)));
543	    }
544	
545	    #[test]
546	    fn zombie_child_is_found_and_reaped() {
547	        let mut t = seeded();
548	        let parent = STUB_E_PROC_NR.get() as usize;
549	        let slot = alloc_slot_in(&t).unwrap();
550	        let pid = set_child_in(&mut t, slot, parent, 0xABCD);
551	
552	        // Before exit: a live child, no zombie.
553	        assert!(has_live_child_in(&t, parent));
554	        assert_eq!(find_zombie_child_in(&t, parent), None);
555	
556	        set_zombie_in(&mut t, slot, 0x0500);
557	        // Now a zombie, no longer counted as a live child.
558	        assert!(!has_live_child_in(&t, parent));
559	        assert_eq!(find_zombie_child_in(&t, parent), Some((slot, pid, 0x0500)));
560	
561	        // Reap frees the slot.
562	        cleanup_in(&mut t, slot);
563	        assert_eq!(find_zombie_child_in(&t, parent), None);
564	        assert!(!in_use_in(&t, slot));
565	        assert_eq!(alloc_slot_in(&t), Some(slot)); // slot is reusable again
566	    }
567	
568	    #[test]
569	    fn waiting_flag_round_trips() {
570	        let mut t = seeded();
571	        let parent = STUB_E_PROC_NR.get() as usize;
572	        assert!(!is_waiting_in(&t, parent));
573	        set_waiting_in(&mut t, parent, true);
574	        assert!(is_waiting_in(&t, parent));
575	        set_waiting_in(&mut t, parent, false);
576	        assert!(!is_waiting_in(&t, parent));
577	    }
578	
579	    #[test]
580	    fn has_live_child_is_false_without_children() {
581	        let t = seeded();
582	        // Stub A has no children (parents are INIT-parented, none point at A).
583	        assert!(!has_live_child_in(&t, STUB_A_PROC_NR.get() as usize));
584	    }
585	
586	    #[test]
587	    fn out_of_range_slots_are_inert() {
588	        let mut t = seeded();
589	        assert!(!in_use_in(&t, NR_MPROCS));
590	        assert_eq!(parent_of_in(&t, NR_MPROCS), None);
591	        assert_eq!(endpoint_of_in(&t, NR_MPROCS), None);
592	        // Mutators on an out-of-range slot are no-ops, not panics.
593	        set_zombie_in(&mut t, NR_MPROCS, 0);
594	        set_waiting_in(&mut t, NR_MPROCS, true);
595	        cleanup_in(&mut t, NR_MPROCS);
596	    }
597	}
